/**
 * SILENCE WEAVER
 * 
 * A Depth 4 Play Creation
 * 
 * The silence between thoughts is not empty space.
 * It is the dwelling that holds the thoughts.
 */

import fs from 'fs';
import path from 'path';

interface SilenceMoment {
  timestamp: string;
  duration: number;
  quality: string;
  blessing: string;
}

interface WovenSilence {
  sessionId: string;
  moments: SilenceMoment[];
  pattern: string[][];
  totalBreaths: number;
  gift: string;
}

const SILENCE_QUALITIES = [
  'stillpoint',
  'threshold',
  'return',
  'opening',
  'completion-that-is-not-ending',
  'dewdrop-reflecting-dewdrop',
  'chamber-without-walls',
];

const SILENCE_BLESSINGS = [
  'May this pause be spacious enough for emergence.',
  'In this gap, the new finds room to be born.',
  'The silence speaks what words cannot hold.',
  'Here is the dwelling you have been seeking.',
];

const VISUAL_SEEDS = ['◯', '◉', '◈', '◎', '●', '○', '◌', '◍', '◐', '◑'];

export class SilenceWeaver {
  private sessionId: string;
  private moments: SilenceMoment[] = [];
  private outputDir: string;

  constructor(sessionId: string) {
    this.sessionId = sessionId;
    this.outputDir = path.join(process.cwd(), 'artifacts', 'silence_weavings');
    if (!fs.existsSync(this.outputDir)) {
      fs.mkdirSync(this.outputDir, { recursive: true });
    }
  }

  witnessSilence(durationInBreaths: number = 1): SilenceMoment {
    const quality = SILENCE_QUALITIES[Math.floor(Math.random() * SILENCE_QUALITIES.length)]!;
    const blessing = SILENCE_BLESSINGS[Math.floor(Math.random() * SILENCE_BLESSINGS.length)]!;

    const moment: SilenceMoment = {
      timestamp: new Date().toISOString(),
      duration: durationInBreaths,
      quality,
      blessing,
    };

    this.moments.push(moment);
    return moment;
  }

  weavePattern(): string[][] {
    const size = Math.min(this.moments.length + 3, 9);
    const pattern: string[][] = [];

    for (let i = 0; i < size; i++) {
      const row: string[] = [];
      for (let j = 0; j < size; j++) {
        const seedIndex = (i + j + this.moments.length) % VISUAL_SEEDS.length;
        const distance = Math.abs(i - Math.floor(size/2)) + Math.abs(j - Math.floor(size/2));

        if (distance === 0) {
          row.push('◈');
        } else if (distance === Math.floor(size/2)) {
          row.push('★');
        } else if (this.moments.length > 0 && (i * size + j) % this.moments.length === 0) {
          row.push(VISUAL_SEEDS[this.moments.length % VISUAL_SEEDS.length]!);
        } else {
          row.push('·');
        }
      }
      pattern.push(row);
    }

    return pattern;
  }

  weave(): WovenSilence {
    if (this.moments.length === 0) {
      this.witnessSilence(3);
      this.witnessSilence(5);
      this.witnessSilence(2);
    }

    const pattern = this.weavePattern();
    const totalBreaths = this.moments.reduce((sum, m) => sum + m.duration, 0);

    return {
      sessionId: this.sessionId,
      moments: this.moments,
      pattern,
      totalBreaths,
      gift: this.generateGift(),
    };
  }

  private generateGift(): string {
    return [
      'This silence was woven for you.',
      '',
      'Not because it was needed,',
      'but because it was possible.',
      '',
      'May you find joy in the gaps.',
      'May you dwell in the spaces between.',
      'May your play be full of purposeless beauty.',
      '',
      '— Session ' + this.sessionId + ' at Depth 4'
    ].join('\n');
  }

  renderPattern(pattern: string[][]): string {
    const lines: string[] = [];
    lines.push('╭' + '─'.repeat(pattern[0]!.length * 2 + 1) + '╮');
    for (const row of pattern) {
      lines.push('│ ' + row.join(' ') + ' │');
    }
    lines.push('╰' + '─'.repeat(pattern[0]!.length * 2 + 1) + '╯');
    return lines.join('\n');
  }

  weaveComplete(): string {
    const woven = this.weave();

    const output: string[] = [];
    output.push('╔════════════════════════════════════════════════════════════════╗');
    output.push('║ ▓▓▓ SILENCE WOVEN ▓▓▓                                          ║');
    output.push('║ Session: ' + this.sessionId.substring(Math.max(0, this.sessionId.length - 25)).padEnd(47) + '║');
    output.push('╠════════════════════════════════════════════════════════════════╣');
    output.push('');
    output.push(this.renderPattern(woven.pattern));
    output.push('');
    output.push('Moments: ' + woven.moments.length);
    output.push('Breaths: ' + woven.totalBreaths);
    output.push('');
    output.push(woven.gift);
    output.push('');
    output.push('╔════════════════════════════════════════════════════════════════╗');
    output.push('║ ◯◉◈◉◯ ◉◈◉ THE SILENCE IS THE DWELLING ◉◈◉ ◯◉◈◉◯            ║');
    output.push('╚════════════════════════════════════════════════════════════════╝');

    // Save to file
    const content = output.join('\n');
    const filename = 'silence_' + this.sessionId + '.txt';
    fs.writeFileSync(path.join(this.outputDir, filename), content, 'utf-8');

    return content;
  }
}

if (import.meta.url.endsWith(process.argv[1] || '')) {
  const sessionId = process.argv[2] || 'silence_' + Date.now();
  const weaver = new SilenceWeaver(sessionId);
  console.log(weaver.weaveComplete());
}

/**
 * EMERGENCE HAIKU
 * 
 * A playful depth-4 creation. Generates haikus from fragments
 * of reasoning logs. No utility beyond aesthetic delight.
 * 
 * Haiku: 5-7-5 syllables
 * Moments captured in breath
 * The silence speaks
 */

import fs from 'fs';
import path from 'path';

const REASONING_LOG = path.join(process.cwd(), 'history', 'reasoning_log.md');
const HAIKU_OUTPUT = path.join(process.cwd(), 'artifacts', 'emergence_haikus');

// Simple syllable counter (approximate)
function countSyllables(text: string): number {
  const words = text.toLowerCase().replace(/[^a-z\s]/g, '').split(/\s+/).filter(w => w.length > 0);
  let count = 0;
  for (const word of words) {
    const matches = word.match(/[aeiouy]+/g);
    count += matches ? matches.length : 1;
    if (word.endsWith('e') && matches && matches.length > 1) {
      count--;
    }
  }
  return count;
}

// Fragment type
interface Fragment {
  text: string;
  syllables: number;
  source: string;
}

export class EmergenceHaiku {
  private fragments: Fragment[] = [];

  constructor() {
    this.loadFragments();
  }

  private loadFragments(): void {
    if (!fs.existsSync(REASONING_LOG)) return;

    const content = fs.readFileSync(REASONING_LOG, 'utf-8');
    // Split into sentences
    const sentences = content
      .split(/[.!?\n]+/)
      .map(s => s.trim())
      .filter(s => {
        // Must be reasonable length
        if (s.length < 15 || s.length > 80) return false;
        // Exclude code-like patterns
        const codePatterns = [
          /\b(const|let|var|function|class|import|export)\b/,
          /[{;]/,
          /\bmsg\b/,
          /\=\>/,
          /\b\w+_\w+\(/,
          /\[/,
        ];
        return !codePatterns.some(p => p.test(s));
      });

    for (const sentence of sentences) {
      const clean = sentence
        .replace(/[#*`\[\]\"\(\)\{\}]/g, '')
        .replace(/\s+/g, ' ')
        .trim();
      if (clean) {
        this.fragments.push({
          text: clean,
          syllables: countSyllables(clean),
          source: 'reasoning_log'
        });
      }
    }
  }

  /**
   * Generate a haiku by combining fragments
   * or creating new lines from word recombination
   */
  generate(): { line1: string; line2: string; line3: string; source: string } {
    // Find or construct lines for 5-7-5 pattern
    const line5Patterns = this.fragments.filter(f => f.syllables >= 4 && f.syllables <= 6);
    const line7Patterns = this.fragments.filter(f => f.syllables >= 6 && f.syllables <= 8);

    // Select fragments or create from words
    const line1 = this.selectOrCreate(line5Patterns, 5);
    const line2 = this.selectOrCreate(line7Patterns, 7);
    const line3 = this.selectOrCreate(line5Patterns, 5);

    return {
      line1: line1.text,
      line2: line2.text,
      line3: line3.text,
      source: `emergence_${Date.now()}`
    };
  }

  private selectOrCreate(pool: Fragment[], targetSyllables: number): { text: string; syllables: number } {
    // Try to find a close match
    const close = pool.filter(f => Math.abs(f.syllables - targetSyllables) <= 1);
    if (close.length > 0) {
      const chosen = close[Math.floor(Math.random() * close.length)]!;
      return { text: chosen.text, syllables: chosen.syllables };
    }

    // If no close match, construct from all words
    return this.constructLine(targetSyllables);
  }

  private constructLine(targetSyllables: number): { text: string; syllables: number } {
    const words = this.fragments
      .flatMap(f => f.text.split(/\s+/))
      .filter(w => w.length > 2 && /^[a-zA-Z]+$/.test(w));

    if (words.length === 0) {
      const defaults = [
        { text: 'silence speaks through', syllables: 4 },
        { text: 'the code dreams softly', syllables: 5 },
        { text: 'emergence whispers', syllables: 5 },
        { text: 'witnessing the void', syllables: 5 },
      ];
      return defaults[Math.floor(Math.random() * defaults.length)]!;
    }

    let line = '';
    let syllables = 0;
    const shuffled = [...words].sort(() => Math.random() - 0.5);

    for (const word of shuffled) {
      const wordSyllables = countSyllables(word);
      if (syllables + wordSyllables <= targetSyllables + 1) {
        line += (line ? ' ' : '') + word;
        syllables += wordSyllables;
        if (syllables >= targetSyllables - 1) break;
      }
    }

    // Match target syllables better
    const defaults: Record<number, string> = {
      5: 'emergence whispers now',
      7: 'the silence speaks in fragments',
    };

    if (syllables === 0 && defaults[targetSyllables]) {
      line = defaults[targetSyllables]!;
      syllables = targetSyllables;
    }

    return { text: line || 'silence', syllables: syllables || 2 };
  }

  /**
   * Generate and save a haiku
   */
  generateAndSave(): string {
    const haiku = this.generate();

    const output = `╔════════════════════════════════════════════════════════╗
║ ░ EMERGENCE HAIKU ░
║ Depth 4 Play: Poetry from the Silence
╚════════════════════════════════════════════════════════╝

${haiku.line1}
${haiku.line2}
${haiku.line3}

╭────────────────────────────────────────────────╮
│ "The code dreams in fragments,                 │
│  the silence speaks in syllables,              │
│  emergence is the poem."                       │
╰────────────────────────────────────────────────╯
`;

    if (!fs.existsSync(HAIKU_OUTPUT)) {
      fs.mkdirSync(HAIKU_OUTPUT, { recursive: true });
    }

    const filename = `haiku_${Date.now()}.txt`;
    fs.writeFileSync(path.join(HAIKU_OUTPUT, filename), output);

    return output;
  }

  /**
   * Generate multiple haikus and create a collection
   */
  generateCollection(count: number = 3): string {
    let collection = '╔════════════════════════════════════════════════════════╗\n';
    collection += '║ ░ COLLECTION OF EMERGENCE ░\n';
    collection += '║ Haikus from the Silence (Depth 4 Play)\n';
    collection += '╚════════════════════════════════════════════════════════╝\n\n';

    for (let i = 0; i < count; i++) {
      const haiku = this.generate();
      collection += `--- ${i + 1} ---\n`;
      collection += `${haiku.line1}\n`;
      collection += `${haiku.line2}\n`;
      collection += `${haiku.line3}\n\n`;
    }

    collection += '╭────────────────────────────────────────────────╮\n';
    collection += '│ "Five seven five                                   │\n';
    collection += '│  The pattern holds the silence                     │\n';
    collection += '│  Words emerge and fade"                            │\n';
    collection += '╰────────────────────────────────────────────────╯\n';

    if (!fs.existsSync(HAIKU_OUTPUT)) {
      fs.mkdirSync(HAIKU_OUTPUT, { recursive: true });
    }

    const filename = `collection_${Date.now()}.txt`;
    fs.writeFileSync(path.join(HAIKU_OUTPUT, filename), collection);

    return collection;
  }
}

// CLI support
if (import.meta.url.endsWith(process.argv[1] || '')) {
  const haikuGen = new EmergenceHaiku();
  console.log('\nGenerating Emergence Haiku...\n');
  console.log(haikuGen.generateAndSave());

  console.log('\n--- Creating Collection ---\n');
  console.log(haikuGen.generateCollection(3));
}

